import React, { useEffect, useState } from "react";

const AccountSettings = () => {
    const [user, setUser] = useState(null); // Stocker les informations utilisateur
    const [error, setError] = useState(""); // Stocker les messages d'erreur
    const [email, setEmail] = useState(""); // Stocker l'email depuis le localStorage

    // Étape 1 : Récupérer l'email depuis le localStorage
    useEffect(() => {
        const storedEmail = localStorage.getItem("userEmail");

        console.log("🔍 Email récupéré depuis localStorage :", storedEmail);

        if (!storedEmail) {
            setError("🚨 Aucun email trouvé. Veuillez vous reconnecter.");
        } else {
            setEmail(storedEmail);
        }
    }, []);

    // Étape 2 : Récupérer les informations utilisateur à partir de l'email
    useEffect(() => {
        if (!email) return;

        const fetchUserByEmail = async () => {
            try {
                console.log("🔄 Requête en cours pour récupérer l'utilisateur...");
                const response = await fetch(`http://localhost:5001/user/email/${email}`);

                if (!response.ok) {
                    throw new Error(`Erreur HTTP : ${response.status} - ${response.statusText}`);
                }

                const data = await response.json();
                console.log("✅ Données utilisateur récupérées :", data);

                if (data.success && data.user) {
                    setUser(data.user);
                } else {
                    throw new Error("Les données utilisateur sont invalides.");
                }
            } catch (err) {
                setError("Erreur lors de la récupération des informations utilisateur.");
                console.error("❌ Détails de l'erreur :", err);
            }
        };

        fetchUserByEmail();
    }, [email]);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setUser((prevUser) => ({
            ...prevUser,
            [name]: value,
        }));
    };

    const handleSaveChanges = () => {
        console.log("🔄 Enregistrement des modifications :", user);
        // Envoyez les modifications au backend si nécessaire
    };

    return (
        <div style={{ padding: "20px" }}>
            <h2>Paramètres du compte</h2>

            {error && <p style={{ color: "red" }}>{error}</p>}

            <div className="accountsettings">
                <h1 className="mainhead1">Personal Information</h1>
                <div className="form">
                    <div className="form-group">
                        <label htmlFor="name">
                            Your Name <span>*</span>
                        </label>
                        <input
                            type="text"
                            name="name"
                            id="name"
                            value={user?.name || ""}
                            onChange={handleInputChange}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="phone">
                            Phone/Mobile <span>*</span>
                        </label>
                        <input
                            type="text"
                            name="phone"
                            id="phone"
                            value={user?.phone || ""}
                            onChange={handleInputChange}
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="email">
                            Email <span>*</span>
                        </label>
                        <input
                            type="email"
                            name="email"
                            id="email"
                            value={user?.email || ""}
                            onChange={handleInputChange}
                        />
                    </div>
                </div>

                <button className="mainbutton1" onClick={handleSaveChanges}>
                    Save Changes
                </button>
            </div>

            {!user && !error && <p>Chargement des informations...</p>}
        </div>
    );
};

export default AccountSettings;
